  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"TSP","domain_id":"craft","opensat_index":1365,"opensat_domain":"Craft and Structure","opensat_raw_id":"f13e0657","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.936Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
